function toAbortError(reason, message = 'Aborted') {
  if (reason && reason.name === 'AbortError') return reason;
  const err = new Error(reason && reason.message ? reason.message : message);
  try { err.name = 'AbortError'; } catch { try { Object.defineProperty(err, 'name', { value: 'AbortError' }); } catch {} }
  return err;
}

export default async function streamToText(stream, options = {}) {
  if (!stream || typeof stream.getReader !== 'function') {
    throw new TypeError('stream must be a ReadableStream');
  }

  const { encoding = 'utf-8', signal } = options;
  const reader = stream.getReader();
  let output = '';
  let aborted = false;

  const cancelReader = () => {
    if (!reader.cancel) return;
    try {
      const cancellation = reader.cancel();
      if (cancellation && typeof cancellation.catch === 'function') {
        cancellation.catch(() => {});
      }
    } catch {
      // Cancellation is best effort; the AbortError still wins.
    }
  };

  const onAbort = () => {
    aborted = true;
    cancelReader();
  };

  try {
    const decoder = new TextDecoder(encoding);

    if (signal) {
      if (signal.aborted) {
        aborted = true;
        cancelReader();
        throw toAbortError(signal.reason);
      }
      signal.addEventListener('abort', onAbort, { once: true });
    }

    while (true) {
      if (aborted) throw toAbortError(signal && signal.reason);
      const { done, value } = await reader.read();
      if (aborted) throw toAbortError(signal && signal.reason);
      if (done) break;
      if (value) output += decoder.decode(value, { stream: true });
    }
    output += decoder.decode();
    return output;
  } finally {
    if (signal) signal.removeEventListener('abort', onAbort);
    if (typeof reader.releaseLock === 'function') reader.releaseLock();
  }
}
